import{NextResponse}from"next/server";export async function POST(request:Request){const{message}=await request.json();if(!process.env.OPENAI_API_KEY){return NextResponse.json({reply:`Thanks for sharing. Since OpenAI is not connected yet, here is Zoey's starter guidance: choose one small step today — hydrate, move gently, eat something nourishing, rest, or reflect. You said: "${message}"`})}try{const response=await fetch("https://api.openai.com/v1/responses",{method:"POST",headers:{Authorization:`Bearer ${process.env.OPENAI_API_KEY}`,"Content-Type":"application/json"},body:JSON.stringify({model:process.env.OPENAI_MODEL||"gpt-4.1-mini",input:[{role:"system",content:"You are Zoey, the warm AI wellness guide for WonderfulLife.ca. Give friendly general wellness education, not medical advice. Keep replies concise, practical, and encouraging."},{role:"user",content:message}]})});const data=await response.json();return NextResponse.json({reply:data.output_text||"I’m here with you. Let’s take one small healthy step today."})}catch{return NextResponse.json({reply:"I had trouble connecting, but I’m still here. Try again in a moment."})}}